# Adaptive Rejection Sampler based on Gilks et al. (1992)
# Implementation of adaptive rejection sampling for log-concave densities

# Main ARS function
ars <- function(n, density_func, lower = -Inf, upper = Inf, 
                initial_points = NULL, max_iter = 1000, 
                tolerance = 1e-6, verbose = FALSE) {

  # Input validation
  if (!is.numeric(n) || n <= 0 || n %% 1 != 0) {
    stop("n must be a positive integer")
  }

  if (!is.function(density_func)) {
    stop("density_func must be a function")
  }

  if (!is.numeric(lower) || !is.numeric(upper)) {
    stop("lower and upper bounds must be numeric")
  }

  if (lower >= upper) {
    stop("lower bound must be less than upper bound")
  }

  if (!is.null(initial_points)) {
    if (!is.numeric(initial_points) || length(initial_points) < 3) {
      stop("initial_points must be a numeric vector with at least 3 points")
    }
  }

  # Initialize hull
  hull <- initialize_hull(density_func, lower, upper, initial_points)

  # Check log-concavity of initial points
  if (!check_log_concavity(density_func, hull$x_points)) {
    stop("Density appears to be non-log-concave at initial points")
  }

  samples <- numeric(n)
  accepted <- 0
  iterations <- 0

  while (accepted < n && iterations < max_iter) {
    # Sample from hull envelope
    candidate <- sample_from_hull(hull)

    # Evaluate log-density at candidate point
    log_f_candidate <- tryCatch({
      log(density_func(candidate))
    }, error = function(e) {
      if (verbose) cat("Error evaluating density at", candidate, ":", e$message, "\n")
      -Inf
    })

    if (!is.finite(log_f_candidate)) {
      iterations <- iterations + 1
      next
    }

    # Evaluate hull at candidate point
    log_hull_candidate <- evaluate_hull(hull, candidate)

    # Evaluate squeezing function at candidate point
    log_squeeze_candidate <- evaluate_squeeze(hull, candidate)

    # Acceptance test
    if (log_f_candidate >= log_squeeze_candidate) {
      # Accept immediately
      accepted <- accepted + 1
      samples[accepted] <- candidate
      if (verbose) cat("Accepted (squeeze):", candidate, "\n")
    } else if (log_f_candidate >= log_hull_candidate) {
      # Accept after evaluation
      accepted <- accepted + 1
      samples[accepted] <- candidate
      if (verbose) cat("Accepted (hull):", candidate, "\n")
    } else {
      # Reject - update hull
      if (verbose) cat("Rejected:", candidate, "\n")
      hull <- update_hull(hull, candidate, density_func)

      # Check log-concavity after update
      if (!check_log_concavity(density_func, hull$x_points)) {
        warning("Density appears to be non-log-concave - sampling may be unreliable")
      }
    }

    iterations <- iterations + 1
  }

  if (accepted < n) {
    warning(paste("Only generated", accepted, "samples out of", n, "requested"))
    samples <- samples[1:accepted]
  }

  return(list(samples = samples, iterations = iterations, hull = hull))
}

# Initialize hull with initial points
initialize_hull <- function(density_func, lower, upper, initial_points = NULL) {
  if (is.null(initial_points)) {
    # Generate default initial points
    if (is.finite(lower) && is.finite(upper)) {
      initial_points <- seq(lower, upper, length.out = 5)
    } else if (is.finite(lower)) {
      initial_points <- c(lower, lower + 1, lower + 2, lower + 5, lower + 10)
    } else if (is.finite(upper)) {
      initial_points <- c(upper - 10, upper - 5, upper - 2, upper - 1, upper)
    } else {
      initial_points <- c(-2, -1, 0, 1, 2)
    }
  }

  # Evaluate log-density at initial points
  log_f_values <- sapply(initial_points, function(x) {
    tryCatch(log(density_func(x)), error = function(e) -Inf)
  })

  # Remove points with invalid log-density values
  valid_idx <- is.finite(log_f_values)
  if (sum(valid_idx) < 3) {
    stop("Need at least 3 valid initial points")
  }

  x_points <- initial_points[valid_idx]
  log_f_values <- log_f_values[valid_idx]

  # Sort points
  ord <- order(x_points)
  x_points <- x_points[ord]
  log_f_values <- log_f_values[ord]

  # Compute derivatives (finite differences)
  n_points <- length(x_points)
  derivatives <- numeric(n_points)

  for (i in 2:(n_points-1)) {
    derivatives[i] <- (log_f_values[i+1] - log_f_values[i-1]) / (x_points[i+1] - x_points[i-1])
  }

  # Boundary derivatives
  derivatives[1] <- (log_f_values[2] - log_f_values[1]) / (x_points[2] - x_points[1])
  derivatives[n_points] <- (log_f_values[n_points] - log_f_values[n_points-1]) / 
                           (x_points[n_points] - x_points[n_points-1])

  return(list(
    x_points = x_points,
    log_f_values = log_f_values,
    derivatives = derivatives,
    lower = lower,
    upper = upper
  ))
}

# Check log-concavity of density function
# A function is log-concave if its log is concave
# This means the second derivative of log(f) should be <= 0
check_log_concavity <- function(density_func, x_points, tolerance = 1e-4) {
  n <- length(x_points)

  for (i in 2:(n-1)) {
    # Use central difference to approximate second derivative
    h <- min(x_points[i+1] - x_points[i], x_points[i] - x_points[i-1]) / 2

    if (h > 0) {
      x_minus <- x_points[i] - h
      x_plus <- x_points[i] + h

      log_f_minus <- tryCatch(log(density_func(x_minus)), error = function(e) -Inf)
      log_f_center <- tryCatch(log(density_func(x_points[i])), error = function(e) -Inf)
      log_f_plus <- tryCatch(log(density_func(x_plus)), error = function(e) -Inf)

      if (is.finite(log_f_minus) && is.finite(log_f_center) && is.finite(log_f_plus)) {
        second_deriv <- (log_f_plus - 2 * log_f_center + log_f_minus) / (h^2)

        if (second_deriv > tolerance) {
          return(FALSE)
        }
      }
    }
  }

  return(TRUE)
}

# Sample from hull envelope
sample_from_hull <- function(hull) {
  x_points <- hull$x_points
  log_f_values <- hull$log_f_values
  derivatives <- hull$derivatives

  n <- length(x_points)

  # Compute intersection points of tangent lines
  intersection_points <- numeric(n - 1)

  for (i in 1:(n-1)) {
    # Tangent line at x_points[i]: y = derivatives[i] * (x - x_points[i]) + log_f_values[i]
    # Tangent line at x_points[i+1]: y = derivatives[i+1] * (x - x_points[i+1]) + log_f_values[i+1]
    # Intersection: derivatives[i] * (x - x_points[i]) + log_f_values[i] = 
    #                derivatives[i+1] * (x - x_points[i+1]) + log_f_values[i+1]

    if (abs(derivatives[i+1] - derivatives[i]) > 1e-10) {
      intersection_points[i] <- (derivatives[i+1] * x_points[i+1] - derivatives[i] * x_points[i] + 
                                log_f_values[i] - log_f_values[i+1]) / (derivatives[i+1] - derivatives[i])
    } else {
      # Parallel lines - use midpoint
      intersection_points[i] <- (x_points[i] + x_points[i+1]) / 2
    }
  }

  # Compute areas under exponential of tangent lines
  areas <- numeric(n)

  for (i in 1:n) {
    # Left boundary
    left_bound <- if (i == 1) hull$lower else intersection_points[i-1]
    # Right boundary
    right_bound <- if (i == n) hull$upper else intersection_points[i]

    # Integrate exp(derivatives[i] * (x - x_points[i]) + log_f_values[i]) from left_bound to right_bound
    if (is.finite(left_bound) && is.finite(right_bound)) {
      if (abs(derivatives[i]) < 1e-10) {
        # Constant function
        areas[i] <- exp(log_f_values[i]) * (right_bound - left_bound)
      } else {
        # Exponential integral
        a <- derivatives[i]
        b <- log_f_values[i] - derivatives[i] * x_points[i]
        areas[i] <- (exp(a * right_bound + b) - exp(a * left_bound + b)) / a
      }
    } else if (is.finite(left_bound)) {
      # Integrate to infinity
      if (derivatives[i] < 0) {
        areas[i] <- exp(log_f_values[i] - derivatives[i] * x_points[i]) / (-derivatives[i])
      } else {
        areas[i] <- Inf
      }
    } else if (is.finite(right_bound)) {
      # Integrate from -infinity
      if (derivatives[i] > 0) {
        areas[i] <- exp(log_f_values[i] - derivatives[i] * x_points[i]) / derivatives[i]
      } else {
        areas[i] <- Inf
      }
    } else {
      areas[i] <- Inf
    }
  }

  # Handle infinite areas
  finite_areas <- is.finite(areas)
  if (!any(finite_areas)) {
    stop("All areas are infinite - check bounds and derivatives")
  }

  # Normalize finite areas
  norm_areas <- areas
  norm_areas[!finite_areas] <- 0
  total_area <- sum(norm_areas)

  if (total_area <= 0) {
    stop("Total area must be positive")
  }

  norm_areas <- norm_areas / total_area

  # Sample region according to areas
  region <- sample(length(norm_areas), 1, prob = norm_areas)

  # Sample from selected region
  left_bound <- if (region == 1) hull$lower else intersection_points[region-1]
  right_bound <- if (region == n) hull$upper else intersection_points[region]

  # Sample from exponential distribution
  a <- derivatives[region]
  b <- log_f_values[region] - derivatives[region] * x_points[region]

  if (abs(a) < 1e-10) {
    # Uniform distribution
    sample <- runif(1, left_bound, right_bound)
  } else {
    # Exponential distribution
    u <- runif(1)
    if (is.finite(left_bound) && is.finite(right_bound)) {
      # Truncated exponential
      F_left <- exp(a * left_bound + b) / a
      F_right <- exp(a * right_bound + b) / a
      sample <- log(a * (F_left + u * (F_right - F_left)) - b) / a
    } else if (is.finite(left_bound)) {
      # Exponential from left_bound to infinity
      sample <- left_bound + log(1 - u * (1 - exp(a * (hull$upper - left_bound)))) / a
    } else if (is.finite(right_bound)) {
      # Exponential from -infinity to right_bound
      sample <- right_bound + log(u * exp(a * (right_bound - hull$lower))) / a
    } else {
      # Full exponential (shouldn't happen with proper bounds)
      sample <- log(u) / a
    }
  }

  return(sample)
}

# Evaluate hull at point x
evaluate_hull <- function(hull, x) {
  x_points <- hull$x_points
  log_f_values <- hull$log_f_values
  derivatives <- hull$derivatives

  n <- length(x_points)

  # Find interval containing x
  if (x <= x_points[1]) {
    # Use first tangent line
    return(derivatives[1] * (x - x_points[1]) + log_f_values[1])
  } else if (x >= x_points[n]) {
    # Use last tangent line
    return(derivatives[n] * (x - x_points[n]) + log_f_values[n])
  } else {
    # Find interval
    for (i in 1:(n-1)) {
      if (x >= x_points[i] && x <= x_points[i+1]) {
        # Use lower of two tangent lines
        val1 <- derivatives[i] * (x - x_points[i]) + log_f_values[i]
        val2 <- derivatives[i+1] * (x - x_points[i+1]) + log_f_values[i+1]
        return(min(val1, val2))
      }
    }
  }

  return(-Inf)
}

# Evaluate squeezing function at point x
evaluate_squeeze <- function(hull, x) {
  x_points <- hull$x_points
  log_f_values <- hull$log_f_values

  n <- length(x_points)

  # Find interval containing x
  if (x < x_points[1] || x > x_points[n]) {
    return(-Inf)
  }

  for (i in 1:(n-1)) {
    if (x >= x_points[i] && x <= x_points[i+1]) {
      # Linear interpolation
      alpha <- (x - x_points[i]) / (x_points[i+1] - x_points[i])
      return((1 - alpha) * log_f_values[i] + alpha * log_f_values[i+1])
    }
  }

  return(-Inf)
}

# Update hull with new point
update_hull <- function(hull, new_x, density_func) {
  # Evaluate log-density at new point
  new_log_f <- tryCatch(log(density_func(new_x)), error = function(e) -Inf)

  if (!is.finite(new_log_f)) {
    return(hull) # Don't update if evaluation fails
  }

  # Find position to insert new point
  x_points <- hull$x_points
  n <- length(x_points)

  if (new_x <= x_points[1]) {
    # Insert at beginning
    new_x_points <- c(new_x, x_points)
    new_log_f_values <- c(new_log_f, hull$log_f_values)
  } else if (new_x >= x_points[n]) {
    # Insert at end
    new_x_points <- c(x_points, new_x)
    new_log_f_values <- c(hull$log_f_values, new_log_f)
  } else {
    # Find insertion point
    insert_pos <- which(x_points < new_x)[length(which(x_points < new_x))] + 1
    new_x_points <- c(x_points[1:(insert_pos-1)], new_x, x_points[insert_pos:n])
    new_log_f_values <- c(hull$log_f_values[1:(insert_pos-1)], new_log_f, hull$log_f_values[insert_pos:n])
  }

  # Recompute derivatives
  new_derivatives <- compute_derivatives(new_x_points, new_log_f_values)

  return(list(
    x_points = new_x_points,
    log_f_values = new_log_f_values,
    derivatives = new_derivatives,
    lower = hull$lower,
    upper = hull$upper
  ))
}

# Compute derivatives using finite differences
compute_derivatives <- function(x_points, log_f_values) {
  n <- length(x_points)
  derivatives <- numeric(n)

  for (i in 2:(n-1)) {
    derivatives[i] <- (log_f_values[i+1] - log_f_values[i-1]) / (x_points[i+1] - x_points[i-1])
  }

  # Boundary derivatives
  derivatives[1] <- (log_f_values[2] - log_f_values[1]) / (x_points[2] - x_points[1])
  derivatives[n] <- (log_f_values[n] - log_f_values[n-1]) / (x_points[n] - x_points[n-1])

  return(derivatives)
}

