  derivatives <- hull$derivatives

  n <- length(x_points)

  # Compute intersection points of tangent lines
  intersection_points <- numeric(n - 1)

  for (i in 1:(n-1)) {
    # Tangent line at x_points[i]: y = derivatives[i] * (x - x_points[i]) + log_f_values[i]
    # Tangent line at x_points[i+1]: y = derivatives[i+1] * (x - x_points[i+1]) + log_f_values[i+1]
