    if (abs(derivatives[i+1] - derivatives[i]) > 1e-10) {
      intersection_points[i] <- (derivatives[i+1] * x_points[i+1] - derivatives[i] * x_points[i] + 
                                log_f_values[i] - log_f_values[i+1]) / (derivatives[i+1] - derivatives[i])
    } else {
      # Parallel lines - use midpoint
      intersection_points[i] <- (x_points[i] + x_points[i+1]) / 2
    }
  }

  # Compute areas under exponential of tangent lines
  areas <- numeric(n)

  for (i in 1:n) {
    # Left boundary
    left_bound <- if (i == 1) hull$lower else intersection_points[i-1]
    # Right boundary
    right_bound <- if (i == n) hull$upper else intersection_points[i]

    # Integrate exp(derivatives[i] * (x - x_points[i]) + log_f_values[i]) from left_bound to right_bound
    if (is.finite(left_bound) && is.finite(right_bound)) {
      if (abs(derivatives[i]) < 1e-10) {
        # Constant function
        areas[i] <- exp(log_f_values[i]) * (right_bound - left_bound)
      } else {
        # Exponential integral
        a <- derivatives[i]
        b <- log_f_values[i] - derivatives[i] * x_points[i]
        areas[i] <- (exp(a * right_bound + b) - exp(a * left_bound + b)) / a
      }
    } else if (is.finite(left_bound)) {
      # Integrate to infinity
      if (derivatives[i] < 0) {
        areas[i] <- exp(log_f_values[i] - derivatives[i] * x_points[i]) / (-derivatives[i])
      } else {
        areas[i] <- Inf
      }
    } else if (is.finite(right_bound)) {
      # Integrate from -infinity
      if (derivatives[i] > 0) {
        areas[i] <- exp(log_f_values[i] - derivatives[i] * x_points[i]) / derivatives[i]
      } else {
        areas[i] <- Inf
      }
    } else {
      areas[i] <- Inf
    }
  }

  # Handle infinite areas
  finite_areas <- is.finite(areas)
  if (!any(finite_areas)) {
    stop("All areas are infinite - check bounds and derivatives")
  }

  # Normalize finite areas
  norm_areas <- areas
  norm_areas[!finite_areas] <- 0
  total_area <- sum(norm_areas)

  if (total_area <= 0) {
    stop("Total area must be positive")
  }

  norm_areas <- norm_areas / total_area

  # Sample region according to areas
  region <- sample(length(norm_areas), 1, prob = norm_areas)

  # Sample from selected region
  left_bound <- if (region == 1) hull$lower else intersection_points[region-1]
  right_bound <- if (region == n) hull$upper else intersection_points[region]

  # Sample from exponential distribution
  a <- derivatives[region]
